const issues = $input.first().json.issues || [];

const grouped = {};
for (const issue of issues) {
  const epic = issue.fields.customfield_10014 || 'No Epic';
  if (!grouped[epic]) grouped[epic] = [];

  const sanitisedSummary = issue.fields.summary
    .replace(/`[^`]+`/g, '[code removed]')
    .replace(/\b[A-Z][a-z]+ [A-Z][a-z]+\b/g, '[Engineer]');

  const latestComment = (issue.fields.comment?.comments || [])
    .slice(-3)
    .map(c => c.body
      .replace(/```[\s\S]*?```/g, '[code block removed]')
      .replace(/`[^`]+`/g, '[code removed]')
      .replace(/\b[A-Z][a-z]+ [A-Z][a-z]+\b/g, '[Engineer]')
    )
    .join(' | ');

  grouped[epic].push({
    key: issue.key,
    summary: sanitisedSummary,
    status: issue.fields.status?.name || 'Unknown',
    latest_comment: latestComment
  });
}

return Object.entries(grouped).map(([epic_name, tickets]) => ({
  json: {
    epic_name,
    ticket_count: tickets.length,
    tickets_sanitised: tickets
      .map(t => `[${t.key}] ${t.summary} (${t.status})${t.latest_comment ? ': ' + t.latest_comment : ''}`)
      .join('\n')
  }
}));

const items = $input.all();

const epicSummaries = items.map(item => {
  let parsed;
  try {
    parsed = JSON.parse(item.json.content[0].text);
  } catch (e) {
    return null;
  }
  const bullets = (parsed.bullets || []).map(b => `• ${b}`).join('\n');
  const blockerLine = parsed.has_blockers ? `\n:red_circle: *Blocker:* ${parsed.blocker_summary}` : '';
  return `*${parsed.epic_name}*\n${bullets}${blockerLine}`;
}).filter(Boolean).join('\n\n');

const now = new Date().toLocaleDateString('en-GB', { weekday: 'long', day: 'numeric', month: 'long' });

return [{
  json: {
    slack_message: `:clipboard: *Daily Engineering Digest — ${now}*\n\n${epicSummaries}\n\n_Powered by Agile Agent • Standup time saved :rocket:_`
  }
}];
